={{
(() => {
  const s = $('Start').first().json || {};

  const inputs = s.inputs || {};
  const resumo = inputs.resumo_lead || {};
  const repasse = inputs.resumo_interno_repasse || {};
  const lead = s.lead || {};
  const chatwoot = s.chatwoot || {};
  const opcoes = s.opcoes || {};

  function clean(v) {
    if (v === undefined || v === null) return '';

    if (typeof v === 'object') {
      try {
        return JSON.stringify(v);
      } catch (e) {
        return '';
      }
    }

    return String(v)
      .replace(/\[object Object\]/gi, '')
      .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
      .replace(/\uFFFD/g, ' ')
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }

  function useful(v) {
    const txt = clean(v).toLowerCase();

    return (
      txt &&
      txt !== 'null' &&
      txt !== 'undefined' &&
      txt !== 'nao_informado' &&
      txt !== 'não_informado' &&
      txt !== 'nao informado' &&
      txt !== 'não informado' &&
      txt !== 'nao_definido' &&
      txt !== 'não_definido' &&
      txt !== 'nao definido' &&
      txt !== 'não definido' &&
      txt !== 'nao_definida' &&
      txt !== 'não_definida' &&
      txt !== 'nao definida' &&
      txt !== 'não definida'
    );
  }

  function pick(...values) {
    for (const v of values) {
      if (useful(v)) return clean(v);
    }

    return '';
  }

  function line(label, value) {
    const v = clean(value);
    return v ? `${label}: ${v}` : '';
  }

  const tutorNome = pick(resumo.tutor_nome, lead.sender_name);
  const tutorTelefone = pick(resumo.tutor_telefone, lead.phone);
  const servico = pick(resumo.servico_interesse);
  const status = clean(inputs.status_lead);
  const intencao = clean(inputs.ultima_intencao);
  const evento = clean(inputs.evento_sistema);
  const proximaAcao = clean(inputs.proxima_acao);
  const observacoes = pick(resumo.observacoes, repasse.observacoes);

  const dadosCao = [
    line('Nome do cão', resumo.cao_nome),
    line('Idade', resumo.cao_idade_anos),
    line('Raça', resumo.cao_raca),
    line('Porte', resumo.cao_porte),
    line('Sexo', resumo.cao_sexo),
    line('Castrado', resumo.cao_castrado),
    line('Vacinas', resumo.cao_vacinas_ok),
    line('Antipulgas', resumo.cao_antipulgas_ok),
    line('Perfil comportamental', resumo.cao_perfil_comportamental),
    line('Obs. comportamento', resumo.cao_comportamento_observacoes)
  ].filter(Boolean);

  const dadosOperacionais = [
    line('Serviço', servico),
    line('Unidade', resumo.unidade_preferida),
    line('Período desejado', resumo.periodo_desejado),
    line('Data desejada', resumo.data_desejada),
    line('Check-in', resumo.data_checkin_desejada),
    line('Check-out', resumo.data_checkout_desejada),
    line('Pagamento', inputs.status_pagamento),
    line('Comprovante recebido', resumo.comprovante_recebido === true ? 'sim' : 'não'),
    line('Tipo comprovante', resumo.tipo_comprovante)
  ].filter(Boolean);

  const resumoTexto = [
    '⬇️Resumo do Lead⬇️',
    '',
    line('Tutor', tutorNome),
    line('Telefone', tutorTelefone),
    line('Status', status),
    line('Intenção', intencao),
    line('Evento', evento),
    '',
    '🐶 Dados do cão',
    ...dadosCao,
    '',
    '📌 Operacional',
    ...dadosOperacionais,
    '',
    line('Próxima ação', proximaAcao),
    line('Observações', observacoes)
  ]
    .filter((linha, index, arr) => {
      if (linha !== '') return true;
      return arr[index - 1] !== '';
    })
    .join('\n')
    .trim();

  return {
    custom_attributes: {
      lead_summary: resumoTexto,

      bruna_status_lead: status,
      bruna_ultima_intencao: intencao,
      bruna_evento_sistema: evento,

      bruna_servico_interesse: servico || '',
      bruna_nome_cao: clean(resumo.cao_nome),
      bruna_raca_cao: clean(resumo.cao_raca),
      bruna_porte_cao: clean(resumo.cao_porte),
      bruna_sexo_cao: clean(resumo.cao_sexo),
      bruna_castrado: clean(resumo.cao_castrado),
      bruna_perfil_comportamental: clean(resumo.cao_perfil_comportamental),
      bruna_comportamento_observacoes: clean(resumo.cao_comportamento_observacoes),

      bruna_deve_repassar_humano: inputs.deve_repassar_humano === true,
      bruna_comprovante_recebido: resumo.comprovante_recebido === true,
      bruna_labels: Array.isArray(opcoes.labels_new) ? opcoes.labels_new.join(', ') : '',
      bruna_conversation_id: chatwoot.conversation_id || ''
    }
  };
})()
}}

