(() => {
  const s = $('Start').first().json || {};

  const inputs = s.inputs || {};
  const message = s.message || {};
  const opcoes = s.opcoes || {};
  const chatwoot = s.chatwoot || {};

  function clean(v) {
    if (v === undefined || v === null) return '';

    return String(v)
      .replace(/\[object Object\]/gi, '')
      .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
      .replace(/\uFFFD/g, ' ')
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }

  const isFup =
    opcoes.eh_fup === true ||
    inputs.evento_sistema === 'FOLLOWUP_DISPARADO';

  const modality = message.message_modality || 'text_only';
  const messageId = chatwoot.message_id || message.current_message_id || message.last_message_id || '';

  const textoPorArray = Array.isArray(inputs.mensagens_resposta)
    ? inputs.mensagens_resposta.map(clean).filter(Boolean).join('\n\n')
    : '';

  const textoResposta = clean(
    message.clean_answer ||
    textoPorArray ||
    ''
  );

  if (!textoResposta) {
    throw new Error('Resposta Bruna bloqueada: texto vazio.');
  }

  return {
    content: textoResposta,
    message_type: 'outgoing',
    private: false,
    content_type: 'text',
    content_attributes: (!isFup && modality !== 'text_only' && messageId)
      ? { in_reply_to: messageId }
      : {}
  };
})()
}}

