parameters.jsonBody:
={{
(() => {
  const s = $('Start').first().json || {};
  const opcoes = s.opcoes || {};
  const message = s.message || {};
  const inputs = s.inputs || {};

  const clean = (v) => {
    if (v === undefined || v === null) return '';
    return String(v)
      .replace(/\[object Object\]/gi, '')
      .replace(/[\u200B-\u200D\u2060\uFEFF]/g, ' ')
      .replace(/\uFFFD/g, ' ')
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  };

  const mensagensBruna = Array.isArray(inputs.mensagens_resposta)
    ? inputs.mensagens_resposta.map(clean).filter(Boolean).join('\n\n')
    : '';

  const textoResposta = clean(
    message.clean_answer ||
    mensagensBruna ||
    message.content ||
    ''
  );

  const textoNota = clean(
    opcoes.nota_privada_texto ||
    inputs.nota_privada_texto ||
    ''
  );

  const texto = textoNota || clean(`
[NOTA PRIVADA BRUNA]
Status: ${inputs.status_lead || 'não informado'}
Intenção: ${inputs.ultima_intencao || 'não informada'}
Evento: ${inputs.evento_sistema || 'sem evento'}

Próxima ação:
${inputs.proxima_acao || 'sem próxima ação registrada'}

Mensagem da Bruna:
${textoResposta || 'sem mensagem registrada'}
`);

  return {
    content: texto,
    message_type: 'outgoing',
    private: true,
    content_type: 'text'
  };
})()
}}

conditions.leftValue:
={{ (() => {
  const s = $('Start').first().json;

  return (
    s.opcoes?.acionar_humano === true ||
    (
      s.opcoes?.acionar_humano !== false &&
      s.opcoes?.envia_chatwoot !== false &&
      (
        s.inputs?.deve_repassar_humano === true ||
        s.inputs?.status_lead === 'TRANSFERIDO_FLAVIA' ||
        s.inputs?.evento_sistema === 'REPASSE_FLAVIA'
      )
    )
  );
})() }}
